#include <bits/stdc++.h>
using namespace std;
#define int unsigned long long
const int b=1e9+7,maxn=1e6+5;
int h[maxn],p[maxn],sa[maxn];
void init_hash(const string &s) {
	int n=s.length();
	p[0]=1;
	for(int i=1; i<=n; i++) {
		p[i]=p[i-1]*b;
		h[i]=h[i-1]*b+s[i];
	}
}
int get_hash(int l,int r) {
	return h[r]-h[l-1]*p[r-l+1];
}
int n;
int find_pos(int x,int y) {
	int l=0,r=min(n-x+1,n-y+1)+1;
	while(l+1<r) {
		int mid=l+r>>1;
		if(get_hash(x,x+mid-1)==get_hash(y,y+mid-1)) {
			l=mid;
		} else {
			r=mid;
		}
	}
	return l;
}
string s;
bool cmp(int l,int r) {
	int p=find_pos(l,r);
	return s[l+p]<s[r+p];
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>s;
	n=s.length();
	s=' '+s;
	init_hash(s);
	for(int i=1; i<=n; i++) {
		sa[i]=i;
	}
	sort(sa+1,sa+1+n,cmp);
	for(int i=1; i<=n; i++) {
		cout<<sa[i]-1<<" ";
	}
	cout<<"\n";
	for(int i=1; i<=n; i++) {
		cout<<find_pos(sa[i],sa[i-1])<<" ";
	}
	return 0;
}
